from dataclasses import dataclass, field
from langchain_openai import ChatOpenAI
from langchain_core.messages import (
    BaseMessage, HumanMessage, AIMessage, SystemMessage
)
from langchain_core.prompts import ChatPromptTemplate, MessagesPlaceholder
from langchain.chains import create_history_aware_retriever, create_retrieval_chain
from langchain.chains.combine_documents import create_stuff_documents_chain
import tiktoken

ENCODER = tiktoken.get_encoding("cl100k_base")

@dataclass
class ConversationalRAG:
    vectorstore: object
    system_prompt: str = (
        "Answer using only the provided context. Cite as [N]. "
        "Say 'I don't know' if the context is insufficient."
    )
    context_window: int = 128_000
    max_answer_tokens: int = 2_048
    max_k: int = 12
    avg_chunk_tokens: int = 450
    keep_last_turns: int = 5
    summary_threshold_turns: int = 10
    chat_history: list[BaseMessage] = field(default_factory=list)

    def _count_tokens(self, text: str) -> int:
        return len(ENCODER.encode(text))

    def _msg_tokens(self, msgs: list[BaseMessage]) -> int:
        return sum(4 + self._count_tokens(m.content) for m in msgs) + 2

    def _context_budget(self) -> int:
        sys_tok = self._count_tokens(self.system_prompt) + 4
        hist_tok = self._msg_tokens(self.chat_history)
        return max(0, self.context_window - self.max_answer_tokens - sys_tok - hist_tok)

    def _dynamic_k(self) -> int:
        return max(1, min(self._context_budget() // self.avg_chunk_tokens, self.max_k))

    def _maybe_compress(self) -> None:
        pairs = [
            (self.chat_history[i], self.chat_history[i + 1])
            for i in range(0, len(self.chat_history) - 1, 2)
            if isinstance(self.chat_history[i], HumanMessage)
            and isinstance(self.chat_history[i + 1], AIMessage)
        ]
        if len(pairs) <= self.summary_threshold_turns:
            return
        to_summarise = [m for pair in pairs[:-self.keep_last_turns] for m in pair]
        recent       = [m for pair in pairs[-self.keep_last_turns:] for m in pair]
        summary      = summarise_history(to_summarise)   # from previous section
        self.chat_history = [
            SystemMessage(content=f"[Summary] {summary}")
        ] + recent

    def chat(self, question: str) -> str:
        self._maybe_compress()
        k = self._dynamic_k()

        llm = ChatOpenAI(model="gpt-4o-mini", temperature=0.0, max_tokens=self.max_answer_tokens)

        # Condenser for follow-up questions
        condenser_prompt = ChatPromptTemplate.from_messages([
            ("system", "Reformulate as a standalone question or return unchanged."),
            MessagesPlaceholder("chat_history"),
            ("human", "{input}"),
        ])
        retriever = self.vectorstore.as_retriever(search_kwargs={"k": k})
        history_aware_retriever = create_history_aware_retriever(
            llm, retriever, condenser_prompt
        )

        qa_prompt = ChatPromptTemplate.from_messages([
            ("system", self.system_prompt + "\n\nContext:\n{context}"),
            MessagesPlaceholder("chat_history"),
            ("human", "{input}"),
        ])
        qa_chain = create_stuff_documents_chain(llm, qa_prompt)
        rag_chain = create_retrieval_chain(history_aware_retriever, qa_chain)

        result = rag_chain.invoke({
            "input": question,
            "chat_history": self.chat_history,
        })
        answer = result["answer"]

        # Update history
        self.chat_history.append(HumanMessage(content=question))
        self.chat_history.append(AIMessage(content=answer))
        return answer
